import { NextResponse } from "next/server";

export async function GET() {
  const secretKey = process.env.LIVEBLOCKS_SECRET_KEY;
  if (!secretKey) {
    return NextResponse.json(
      { error: "LIVEBLOCKS_SECRET_KEY is not configured" },
      { status: 500 }
    );
  }

  try {
    const response = await fetch("https://api.liveblocks.io/v2/rooms", {
      headers: {
        Authorization: `Bearer ${secretKey}`,
      },
    });

    if (!response.ok) {
      const errorText = await response.text();
      return NextResponse.json(
        { error: `Liveblocks API error: ${response.status} - ${errorText}` },
        { status: response.status }
      );
    }

    const data = await response.json();
    // Forward the response data. Shape: { nextCursor, data: [...] }
    return NextResponse.json({ data: data.data || [] });
  } catch (error) {
    console.error("Error fetching rooms:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}

export async function POST() {
  const secretKey = process.env.LIVEBLOCKS_SECRET_KEY;
  if (!secretKey) {
    return NextResponse.json(
      { error: "LIVEBLOCKS_SECRET_KEY is not configured" },
      { status: 500 }
    );
  }

  const runId = process.env.NEXT_PUBLIC_ZEALT_RUN_ID || "";
  const timestamp = Date.now();
  const roomId = `harbor-created-${runId}-${timestamp}`;

  try {
    const response = await fetch("https://api.liveblocks.io/v2/rooms", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${secretKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        id: roomId,
        defaultAccesses: ["room:write"],
      }),
    });

    if (!response.ok) {
      const errorText = await response.text();
      return NextResponse.json(
        { error: `Liveblocks API error: ${response.status} - ${errorText}` },
        { status: response.status }
      );
    }

    const createdRoom = await response.json();
    return NextResponse.json({ id: createdRoom.id }, { status: 201 });
  } catch (error) {
    console.error("Error creating room:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}

"use client";

import { useEffect, useState } from "react";

export default function Page() {
  const [rooms, setRooms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [creating, setCreating] = useState(false);
  const [error, setError] = useState(null);

  const fetchRooms = async () => {
    try {
      const res = await fetch("/api/rooms");
      if (!res.ok) {
        throw new Error(`Failed to fetch rooms: ${res.status}`);
      }
      const data = await res.json();
      setRooms(data.data || []);
      setError(null);
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRooms();
  }, []);

  const handleCreateRoom = async () => {
    setCreating(true);
    setError(null);
    try {
      const res = await fetch("/api/rooms", {
        method: "POST",
      });
      if (!res.ok) {
        throw new Error(`Failed to create room: ${res.status}`);
      }
      // On success, refresh the list
      await fetchRooms();
    } catch (err) {
      console.error(err);
      setError(err.message);
    } finally {
      setCreating(false);
    }
  };

  return (
    <main style={{ padding: "2rem", fontFamily: "sans-serif", maxWidth: "800px", margin: "0 auto" }}>
      <h1 style={{ marginBottom: "1.5rem" }}>Liveblocks Rooms</h1>

      <div style={{ marginBottom: "2rem" }}>
        <button
          onClick={handleCreateRoom}
          disabled={creating}
          style={{
            padding: "0.75rem 1.5rem",
            fontSize: "1rem",
            backgroundColor: creating ? "#ccc" : "#0070f3",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: creating ? "not-allowed" : "pointer",
          }}
        >
          {creating ? "Creating..." : "Create Room"}
        </button>
      </div>

      {error && (
        <div style={{ color: "red", marginBottom: "1rem", padding: "1rem", backgroundColor: "#ffebee", borderRadius: "4px" }}>
          Error: {error}
        </div>
      )}

      {loading ? (
        <p>Loading rooms...</p>
      ) : (
        <div>
          <h2 style={{ fontSize: "1.25rem", marginBottom: "1rem" }}>Room List ({rooms.length})</h2>
          {rooms.length === 0 ? (
            <p>No rooms found.</p>
          ) : (
            <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
              {rooms.map((room) => (
                <li
                  key={room.id}
                  data-testid="room-row"
                  style={{
                    padding: "1rem",
                    borderBottom: "1px solid #eaeaea",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                  }}
                >
                  <span style={{ fontWeight: "bold" }}>{room.id}</span>
                  <span style={{ color: "#666", fontSize: "0.875rem" }}>
                    Created: {new Date(room.createdAt || Date.now()).toLocaleString()}
                  </span>
                </li>
              ))}
            </ul>
          )}
        </div>
      )}
    </main>
  );
}

